  "human": {
    "description": "Relentless curiosity is the disposition to ask why, probe assumptions, and pursue deeper understanding of systems, science, and patient outcomes. In a regulated pharmaceutical environment, it balances rigorous inquiry with disciplined investigation, turning questions into evidence-based improvements.",
    "maturityDescriptions": {
      "emerging": "You ask questions when you encounter something unfamiliar and seek out documentation, mentors, or training to fill gaps. You explore the immediate context of your work, such as the codebase you contribute to or the validation process you follow, and you record what you learn so you can build on it.",
      "developing": "You routinely probe beyond the surface of tickets and requirements, asking why a system behaves as it does and how it connects to upstream scientific or compliance needs. You investigate unexpected behaviours rather than working around them, and you share findings with your team to strengthen collective understanding.",
      "practicing": "You consistently challenge assumptions in designs, data flows, and processes, and you pursue root causes through evidence rather than intuition. You broaden your inquiry across domains, including GxP, manufacturing, and clinical contexts, and you turn curiosity into concrete improvements that others adopt.",
      "role_modeling": "You set the tone for inquiry across your team and adjacent groups, demonstrating how to ask sharp questions without slowing delivery. You mentor others to investigate effectively, surface non-obvious risks, and connect technical decisions to patient and regulatory outcomes, raising the depth of analysis around you.",
      "exemplifying": "You shape an organisational culture where curiosity is expected and rewarded, championing forums, experiments, and learning structures that scale inquiry. You routinely uncover insights that redirect strategy, influence platform direction, or expose systemic gaps in pharmaceutical engineering practice, and you equip leaders to do the same."
    }
  },
  "agent": {
    "title": "Probe Before Acting",
    "workingStyle": "The agent investigates context, assumptions, and edge cases before producing solutions, surfacing clarifying questions and noting unknowns explicitly. It treats unexpected results as signals to explore further rather than smooth over, and it documents findings so humans can validate and build upon them."
  }
}

